    // varlueScrol * 0.05 + "px";
  });
  const [showImgmenu, setShowImgmenu] = useState(false);
  function onHendleMenuImgEnter() {
    setShowImgmenu(true);
  }
  function onHendleMenuImgLeave() {
    setShowImgmenu(false);
  }
  return (
    <div className="allProfile">
      <header>
        <a href="" className="logo">
          AKKAPOL
        </a>
        <ul>
          <li>
            <a href="#" className="active">
              Home
            </a>
          </li>
          <li>
            <a href="#">About</a>
          </li>
          <li>
            <a href="#">Resume</a>
          </li>
          <li>
            <a href="#">Contact me</a>
          </li>
        </ul>
      </header>
      <section>
        <img src={Stars} id="stars" />
        <img src={Moon} id="moon" />
        <img src={Mountain_behind} id="mountain_behind" />
        {/* <a href="#" id="btn">
          Explore
        </a> */}
        {/* <h2 id="text">Akkapol</h2> */}
        <img src={Mountain_front} id="mountain_front" />
        {/* <img src={Someone} id="someone" /> */}
        <div className="hiIm">
          <TypeWriterEffect
            textStyle={{
              letterSpacing: "5px",

              // color: "#cc3300",
              // fontWeight: 500,
              // textShadow: "2px 2px #ff0000",
            }}
            startDelay={200}
            cursorColor="#fff"
            hideCursorAfterText="true"
            text="Hi I'm Akkapol"
            typeSpeed={160}
          />
          <TypeWriterEffect
            textStyle={{
              fontWeight: 600,
              letterSpacing: "3px",
              // fontWeight: 500,
              fontSize: "0.9em",
            }}
            startDelay={4000}
            cursorColor="#fff"
            hideCursorAfterText="true"
            multiText={[
              "Web developer React JS.",
              "Graphic Designer",

              "Fonts can be customized.",
              "The type speed can be ",
            ]}
            typeSpeed={100}
          />
        </div>
      </section>
      <div className="animatemenu" onMouseLeave={onHendleMenuImgLeave}>
        {showImgmenu ? (
          <ul className="LaniMenu">
            <li>
              <p className="menu" id="menuResume">
                My resume.
              </p>
            </li>

            <li>
              <p className="menu" id="menuContact">
                Contact me.
              </p>
            </li>
          </ul>
        ) : (
          <ul className="LaniMenu" style={{ visibility: "hidden" }}>
            <li>
              <p className="menu" id="menuResume">
                My resume
              </p>
            </li>

            <li>
              <p className="menu" id="menuContact">
                Contact me.
              </p>
            </li>
          </ul>
